#!/usr/bin/env python3
"""
DreamServer PR Analyzer - Generates comprehensive audit data for all 75 open PRs.
Run from the dreamserver-repo directory.
"""

import json
import subprocess
import os
import re
from pathlib import Path
from datetime import datetime

REPO_DIR = Path("/workspace/dreamserver-repo")
AUDIT_DIR = Path("/workspace/dreamserver-audit")

def run_git(args, timeout=30):
    """Run a git command and return stdout."""
    result = subprocess.run(
        ["git"] + args,
        cwd=REPO_DIR,
        capture_output=True,
        text=True,
        timeout=timeout
    )
    return result.stdout.strip(), result.stderr.strip(), result.returncode

def get_pr_diff(pr_num, ref):
    """Get the full diff for a PR."""
    stdout, _, rc = run_git(["diff", f"main...{ref}"])
    return stdout if rc == 0 else ""

def get_pr_diff_stat(pr_num, ref):
    """Get the diff stat for a PR."""
    stdout, _, rc = run_git(["diff", f"main...{ref}", "--stat"])
    return stdout if rc == 0 else ""

def get_pr_files(pr_num, ref):
    """Get the list of changed files for a PR."""
    stdout, _, rc = run_git(["diff", f"main...{ref}", "--name-only"])
    return [f for f in stdout.split('\n') if f] if rc == 0 else []

def get_pr_commits(pr_num, ref):
    """Get the commit log for a PR."""
    stdout, _, rc = run_git(["log", f"main..{ref}", "--oneline"])
    return stdout.split('\n') if rc == 0 and stdout else []

def classify_file(filepath):
    """Classify a file by subsystem and type."""
    subsystems = []

    # Subsystem classification
    if any(x in filepath for x in ['installer/', 'install.sh', 'env-generator', 'setup-wizard']):
        subsystems.append('installer')
    if any(x in filepath for x in ['host-agent', 'dream-host-agent']):
        subsystems.append('host-agent')
    if any(x in filepath for x in ['dashboard-api', 'dashboard/', 'routers/']):
        subsystems.append('dashboard-api')
    if any(x in filepath for x in ['dream-cli', 'dream', 'gpu_reassign', 'dream-shell']):
        subsystems.append('dream-cli')
    if any(x in filepath for x in ['extensions/', 'extension', 'community/']):
        subsystems.append('extensions')
    if any(x in filepath for x in ['scripts/', '.sh']):
        subsystems.append('scripts')
    if any(x in filepath for x in ['.github/', 'ci/', 'workflow']):
        subsystems.append('ci')
    if any(x in filepath for x in ['.md', '.rst', 'docs/']):
        subsystems.append('docs')
    if any(x in filepath for x in ['test', 'spec']):
        subsystems.append('tests')
    if any(x in filepath for x in ['Dockerfile', 'docker-compose', 'compose']):
        subsystems.append('compose')
    if any(x in filepath for x in ['resolver', 'resolve']):
        subsystems.append('resolver')
    if any(x in filepath for x in ['gpu', 'amd', 'rocm', 'ROCm']):
        subsystems.append('gpu')
    if any(x in filepath for x in ['.ps1', '.psm1', 'windows/']):
        subsystems.append('windows')
    if any(x in filepath for x in ['macos', 'darwin', 'apple', 'silicon']):
        subsystems.append('macos')
    if any(x in filepath for x in ['langfuse']):
        subsystems.append('langfuse')
    if any(x in filepath for x in ['openclaw', 'open-webui']):
        subsystems.append('openclaw')
    if any(x in filepath for x in ['jupyter']):
        subsystems.append('jupyter')
    if any(x in filepath for x in ['perplexica']):
        subsystems.append('perplexica')
    if any(x in filepath for x in ['librechat']):
        subsystems.append('librechat')
    if any(x in filepath for x in ['resources/', 'vast', 'p2p']):
        subsystems.append('resources')
    if any(x in filepath for x in ['mobile', 'termux', 'ashell']):
        subsystems.append('mobile')
    if any(x in filepath for x in ['.env', 'schema', '.json']):
        subsystems.append('config')
    if any(x in filepath for x in ['security', 'token', 'auth']):
        subsystems.append('security')
    if any(x in filepath for x in ['bootstrap']):
        subsystems.append('bootstrap')
    if any(x in filepath for x in ['support', 'diagnostic']):
        subsystems.append('support')
    if any(x in filepath for x in ['embeddings']):
        subsystems.append('embeddings')
    if any(x in filepath for x in ['piper', 'audio']):
        subsystems.append('audio')
    if any(x in filepath for x in ['milvus']):
        subsystems.append('milvus')

    if not subsystems:
        subsystems.append('other')

    # Language classification
    lang = 'other'
    if filepath.endswith('.py'):
        lang = 'python'
    elif filepath.endswith('.sh') or filepath in ['dream', 'install', 'bootstrap']:
        lang = 'bash'
    elif filepath.endswith('.js'):
        lang = 'javascript'
    elif filepath.endswith('.ts'):
        lang = 'typescript'
    elif filepath.endswith('.jsx'):
        lang = 'jsx'
    elif filepath.endswith('.tsx'):
        lang = 'tsx'
    elif filepath.endswith('.yaml') or filepath.endswith('.yml'):
        lang = 'yaml'
    elif filepath.endswith('.json'):
        lang = 'json'
    elif filepath.endswith('.md'):
        lang = 'markdown'
    elif filepath.endswith('.ps1'):
        lang = 'powershell'
    elif filepath.endswith('.psm1'):
        lang = 'powershell'
    elif 'Dockerfile' in filepath:
        lang = 'dockerfile'

    return subsystems, lang

def estimate_bounty_tier(diff_size, num_files, subsystems):
    """Estimate bounty tier based on change size and complexity."""
    if diff_size < 2000 and num_files <= 2:
        return "Small ($40)"
    elif diff_size < 20000 and num_files <= 10:
        return "Medium ($150)"
    else:
        return "Large ($400)"

def calculate_risk_score(pr_data):
    """Calculate risk score based on multiple axes."""
    scores = {}

    # Surface area (0-10)
    num_files = len(pr_data.get('files', []))
    if num_files <= 2:
        scores['surface_area'] = 1
    elif num_files <= 5:
        scores['surface_area'] = 3
    elif num_files <= 10:
        scores['surface_area'] = 5
    elif num_files <= 20:
        scores['surface_area'] = 7
    else:
        scores['surface_area'] = 10

    # Test coverage (0-10) - lower is better
    has_tests = any('test' in f.lower() for f in pr_data.get('files', []))
    scores['test_coverage'] = 2 if has_tests else 7

    # Reversibility (0-10) - lower is better
    diff_size = pr_data.get('diff_size', 0)
    if diff_size < 5000:
        scores['reversibility'] = 2
    elif diff_size < 20000:
        scores['reversibility'] = 4
    elif diff_size < 100000:
        scores['reversibility'] = 6
    else:
        scores['reversibility'] = 9

    # Blast radius (0-10)
    subsystems = pr_data.get('subsystems', [])
    critical = {'host-agent', 'installer', 'dashboard-api', 'dream-cli'}
    if any(s in critical for s in subsystems):
        scores['blast_radius'] = 7
    elif len(subsystems) > 3:
        scores['blast_radius'] = 6
    else:
        scores['blast_radius'] = 3

    # Contributor track record (0-10) - lower is better
    author = pr_data.get('author', '')
    if author == 'yasinBursali':
        scores['contributor_risk'] = 1  # Established
    elif author in ['boffin-dmytro', 'y-coffee-dev']:
        scores['contributor_risk'] = 3  # Known
    elif author == 'dependabot[bot]':
        scores['contributor_risk'] = 1  # Automated
    else:
        scores['contributor_risk'] = 7  # Unknown

    # Overall risk (weighted average)
    weights = {
        'surface_area': 0.25,
        'test_coverage': 0.20,
        'reversibility': 0.15,
        'blast_radius': 0.25,
        'contributor_risk': 0.15
    }

    overall = sum(scores[k] * weights[k] for k in weights) / sum(weights.values())
    scores['overall'] = round(overall, 1)

    return scores

def main():
    # Load PR data
    with open('/tmp/pr_full.json') as f:
        prs = json.load(f)

    # Analyze each PR
    for pr in prs:
        if 'error' in pr:
            continue

        pr_num = pr['pr']
        ref = pr['ref']

        # Get detailed info
        commits = get_pr_commits(pr_num, ref)
        files = pr.get('files', [])
        diff_size = pr.get('diff_size', 0)

        # Classify files
        subsystems = set()
        languages = set()
        for f in files:
            subs, lang = classify_file(f)
            subsystems.update(subs)
            languages.add(lang)

        pr['subsystems'] = sorted(subsystems)
        pr['languages'] = sorted(languages)
        pr['commits'] = commits
        pr['bounty_tier'] = estimate_bounty_tier(diff_size, len(files), subsystems)
        pr['risk'] = calculate_risk_score(pr)

    # Save analysis
    with open('/tmp/pr_analysis.json', 'w') as f:
        json.dump(prs, f, indent=2)

    # Print summary
    print(f"Analyzed {len(prs)} PRs")
    for pr in prs:
        if 'error' in pr:
            continue
        print(f"PR #{pr['pr']:>4} | {pr['author']:20s} | risk={pr['risk']['overall']:4.1f} | "
              f"files={len(pr['files']):>3} | subs={','.join(pr['subsystems'][:3])} | "
              f"tier={pr['bounty_tier']}")

if __name__ == '__main__':
    main()
